@@ -362,3 +364,25 @@ func (c *Commander) Stop(ctx context.Context) error {

 	return innerErr
 }
+
+// Reload signals the Agent process to reload its configuration.
+// On non-Windows systems, this uses SIGHUP to trigger configuration reload.
+// On Windows, this falls back to restarting the process since SIGHUP is not available.
+func (c *Commander) Reload(ctx context.Context) error {
+	if c.running.Load() == 0 {
+		return errors.New("agent process is not running")
+	}
+
+	pid := c.cmd.Process.Pid
+	c.logger.Debug("Reloading agent configuration", zap.Int("pid", pid))
+
+	// Use platform-specific reload signaling
+	if err := sendReloadSignal(c.cmd.Process); err != nil {
+		// On Windows, fall back to restart since SIGHUP is not available
+		c.logger.Debug("Reload signal not supported, falling back to restart", zap.Error(err))
+		return c.Restart(ctx)
+	}
+
+	c.logger.Debug("Reload signal sent to agent process for configuration reload", zap.Int("pid", pid))
+	return nil
+}
