			"Agent process is not responding to SIGTERM. Sending SIGKILL to kill forcibly.",
			zap.Int("pid", pid))
		if innerErr = c.cmd.Process.Signal(os.Kill); innerErr != nil {
			return
		}
	}()

	// Wait for process to terminate
	<-c.doneCh

	c.running.Store(0)

	// Let goroutine know process is finished.
	cancel()

	return innerErr
}

// Reload signals the Agent process to reload its configuration using SIGHUP.
// This is a non-blocking operation that leverages the Collector's built-in
// configuration reload capability.
func (c *Commander) Reload(ctx context.Context) error {
	if c.running.Load() == 0 {
		return errors.New("agent process is not running")
	}

	pid := c.cmd.Process.Pid
	c.logger.Debug("Reloading agent configuration", zap.Int("pid", pid))

	// Send SIGHUP to trigger configuration reload
	if err := c.cmd.Process.Signal(syscall.SIGHUP); err != nil {
		return fmt.Errorf("failed to send SIGHUP to agent process: %w", err)
	}

	c.logger.Debug("SIGHUP sent to agent process for configuration reload", zap.Int("pid", pid))
	return nil
}

